INSERT INTO `questions` VALUES (2026,1,'reverse','easy','mov eax, 5 əmri nə edir?','A) EAX registrinə 5 dəyərini yazır','B) 5-i ekrana çıxarır','C) 5 dəfə dövrə edir','D) EAX-ı sıfırlayır',0,'MOV əmri mənbədən hədəfə dəyər kopyalayır. mov eax, 5 — EAX-a 5 yazır.',5,1,'2026-03-25 10:29:30'),(2027,1,'reverse','easy','Binary 1010 ədədinin onluq qarşılığı nədir?','A) 10','B) 12','C) 8','D) 15',0,'1010 = 1×8 + 0×4 + 1×2 + 0×1 = 10',5,1,'2026-03-25 10:29:30'),(2028,1,'reverse','easy','Hexadecimal 0xFF dəyəri onluqda neçədir?','A) 256','B) 255','C) 128','D) 127',1,'0xFF = 15×16 + 15 = 255',5,1,'2026-03-25 10:29:30'),(2029,1,'reverse','easy','Assembly dilində ; (nöqtəli vergül) nə üçündür?','A) Dəyişən elan edir','B) Şərh (comment) yazır','C) Dövrə başladır','D) Funksiyanı çağırır',1,'; simvolu Assembly-də şərh yazmaq üçün istifadə olunur',5,1,'2026-03-25 10:29:30'),(2030,1,'reverse','easy','1 bayt neçə bitdən ibarətdir?','A) 4','B) 8','C) 16','D) 32',1,'1 bayt = 8 bit',5,1,'2026-03-25 10:29:30'),(2031,1,'reverse','medium','mov eax, [ebp-4] əmrində [ebp-4] nədir?','A) Registr dəyəri','B) Yaddaş ünvanı (stack-dəki lokal dəyişən)','C) Sabit ədəd','D) Port nömrəsi',1,'[ebp-4] stack frame-dəki ilk lokal dəyişənin yaddaş ünvanıdır',10,1,'2026-03-25 10:29:30'),(2032,1,'reverse','medium','Little Endian formatda 0x12345678 yaddaşda necə saxlanır?','A) 12 34 56 78','B) 78 56 34 12','C) 87 65 43 21','D) 21 43 65 87',1,'Little Endian — ən kiçik bayt əvvəl: 78, 56, 34, 12',10,1,'2026-03-25 10:29:30'),(2033,1,'reverse','medium','Twos complement formatda -1 dəyəri 8-bit-də necə yazılır?','A) 10000001','B) 11111111','C) 00000001','D) 11111110',1,'-1 = 11111111 (bütün bitlər 1). Twos complement: invert + 1',10,1,'2026-03-25 10:29:30'),(2034,1,'reverse','medium','ASCII cədvəlində A hərfinin kodu neçədir?','A) 97','B) 65','C) 48','D) 90',1,'A = 65 (0x41). Kiçik a = 97 (0x61)',10,1,'2026-03-25 10:29:30'),(2035,1,'reverse','medium','32-bit registr maksimum neçə dəyər saxlaya bilər?','A) 2^16','B) 2^32 (4,294,967,296)','C) 2^8','D) 2^64',1,'32-bit registr 0-dan 2^32-1 = 4,294,967,295 qədər saxlayır',10,1,'2026-03-25 10:29:30'),(2036,1,'reverse','hard','Aşağıdakı kodun nəticəsi nədir?\nmov eax, 0xA\nadd eax, 0x5\nsub eax, 0x3','A) 0xC (12)','B) 0x8 (8)','C) 0xF (15)','D) 0x12 (18)',0,'0xA(10) + 0x5(5) = 0xF(15), 0xF - 0x3(3) = 0xC(12)',20,1,'2026-03-25 10:29:30'),(2037,1,'reverse','hard','Malware analiz zamanı PE faylın magic number-i nədir?','A) ELF','B) MZ (4D 5A)','C) PK','D) 7F 45',1,'Windows PE faylları MZ (Mark Zbikowski) header ilə başlayır: 4D 5A',20,1,'2026-03-25 10:29:30'),(2038,1,'reverse','hard','Stack overflow hücumunda RET ünvanı niyə vacibdir?','A) Məlumatı şifrələyir','B) İcra axınını ələ keçirmək üçün geri qayıtma ünvanını dəyişir','C) Faylı silir','D) Şəbəkəni bağlayır',1,'Stack overflow ilə RET ünvanı dəyişdirilir, shellcode-a jump edilir',20,1,'2026-03-25 10:29:30'),(2039,1,'reverse','hard','IDA Pro-da graph view nəyi göstərir?','A) Yaddaş xəritəsini','B) Funksiyanın control flow graph-ını (basic blocks)','C) Şəbəkə trafikini','D) Fayl sistemini',1,'IDA graph view funksiya daxilindəki basic block-ları və keçidləri göstərir',20,1,'2026-03-25 10:29:30'),(2040,1,'reverse','hard','XOR EAX, EAX əmri nə edir və niyə MOV EAX, 0 əvəzinə istifadə olunur?','A) EAX-ı sıfırlayır — daha qısa opkod, daha sürətli','B) EAX-ı 1 edir','C) EAX-ı invert edir','D) Heç nə etmir',0,'XOR reg, reg registri sıfırlayır. 2 bayt opkod (MOV-un 5 baytına qarşı), pipeline-da daha effektiv',20,1,'2026-03-25 10:29:30'),(2041,2,'reverse','easy','EAX registri nə üçün istifadə olunur?','A) Əsasən hesablama (accumulator) üçün','B) Yalnız ünvan saxlamaq üçün','C) Yalnız sayğac üçün','D) Yalnız I/O üçün',0,'EAX — Accumulator, arifmetik əməliyyatların əsas registri',5,1,'2026-03-25 10:29:30'),(2042,2,'reverse','easy','ESP registri nəyi göstərir?','A) Stack-in yuxarısını (top of stack)','B) Funksiyanın adını','C) Disk ünvanını','D) Ekran bufferini',0,'ESP — Stack Pointer, stack-in hazırkı yuxarı nöqtəsinə işarə edir',5,1,'2026-03-25 10:29:30'),(2043,2,'reverse','easy','EIP registri nədir?','A) Növbəti icra olunacaq əmrin ünvanı','B) Integer pointer','C) I/O port','D) Interrupt handler',0,'EIP — Instruction Pointer, CPU-nun növbəti oxuyacağı əmrin yaddaş ünvanı',5,1,'2026-03-25 10:29:30'),(2044,2,'reverse','easy','PUSH EAX əmri nə edir?','A) EAX dəyərini stack-ə yazır, ESP-ni azaldır','B) EAX-ı silir','C) EAX-ı artırır','D) EAX-dan oxuyur',0,'PUSH — dəyəri stack-ə qoyur, ESP 4 bayt azalır (stack aşağı böyüyür)',5,1,'2026-03-25 10:29:30'),(2045,2,'reverse','easy','POP EBX əmri nə edir?','A) Stack-dən dəyər oxuyub EBX-ə yazır, ESP-ni artırır','B) EBX-i silir','C) EBX-i sıfırlayır','D) Stack-i boşaldır',0,'POP — stack-in yuxarısından dəyəri götürüb registrə yazır, ESP 4 artır',5,1,'2026-03-25 10:29:30'),(2046,2,'reverse','medium','Fetch-Decode-Execute dövrü nədir?','A) CPU-nun hər əmri yerinə yetirmə prosesi: əmri al, deşifrə et, icra et','B) Disk oxuma prosesi','C) Şəbəkə protokolu','D) Kompressor alqoritmi',0,'CPU hər əmr üçün: 1) Yaddaşdan əmri fetch edir, 2) Decode — nə etməli, 3) Execute — icra edir',10,1,'2026-03-25 10:29:30'),(2047,2,'reverse','medium','FLAGS registrindəki ZF (Zero Flag) nə vaxt 1 olur?','A) Nəticə sıfır olduqda','B) Nəticə mənfi olduqda','C) Overflow olduqda','D) Carry olduqda',0,'ZF = 1 əgər son əməliyyatın nəticəsi 0 idisə. CMP EAX, EBX → bərabərdirsə ZF=1',10,1,'2026-03-25 10:29:30'),(2048,2,'reverse','medium','CMP EAX, EBX əmri nə edir?','A) EAX-dan EBX-i çıxır amma nəticəni saxlamır, yalnız flag-ları yeniləyir','B) EAX-ı EBX-ə kopyalayır','C) EAX və EBX-i toplayır','D) EAX-ı sıfırlayır',0,'CMP = SUB nəticəni atmaqla. Yalnız FLAGS registrini yeniləyir',10,1,'2026-03-25 10:29:30'),(2049,2,'reverse','medium','LEA EAX, [EBX+ECX*4+8] əmri nə edir?','A) EBX + ECX×4 + 8 ünvanını EAX-a yazır (yaddaşa müraciət etmədən)','B) Yaddaşdan oxuyur','C) Yaddaşa yazır','D) Stack-ə push edir',0,'LEA — Load Effective Address, ünvanı